<template>
	<view class="body">
		<view class="order">
			<view class="top">
				<view class="left" @click="paste(order.ordersn)">

					<view class="store">{{ order.ordersn }}</view>
					<u-icon name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon>
					<!-- <u-icon name="arrow-right" color="rgb(203,203,203)" :size="26"></u-icon> -->
				</view>
				<view class="right" :style="{
					color:statusColor[order.status].color
				}">{{ order.status_text }}</view>
			</view>
			<view class="item" @click="$util.on(`/pages/goods/detail?id=${order.goods_id}`)">
				<view class="left">
					<image :src="order.goods_img" mode="aspectFill"></image>
				</view>
				<view class="content">
					<view class="title u-line-2">{{ order.goods_name }}</view>
					<view class="type" v-if="order.goods_sku_name">{{ order.goods_sku_name }}</view>
					<view class="type">{{ order.goods_type_text }}</view>
					<view class="progress" v-if="orderProgressVisible">
						<text class="label">下单进度</text><u-line-progress active-color="#2979ff"
							:percent="orderProgressNum"></u-line-progress>
					</view>
					<view class="delivery-time">下单时间 {{ $util.timeFormat(order.create_time,'yyyy-mm-dd hh:MM:ss') }}
					</view>
					<view class="delivery-time" v-if="order.finish_time">完成时间
						{{ $util.timeFormat(order.finish_time,'yyyy-mm-dd hh:MM:ss') }}
					</view>
				</view>
				<view class="right">
					<view class="price">
						￥{{ priceInt(order.price) | showPrice }}
						<text class="decimal">.{{ priceDecimal(order.price) | showPrice}}</text>
					</view>
					<view class="number">x{{ order.quantity }}</view>
					<view v-if="order.has_back_money && order.has_back_money>0" style="color: #ff5500;font-size: 26rpx;">退:{{ order.has_back_money }}</view>
					
				</view>
			</view>
			<view class="total" style="display: flex;justify-content: space-between;align-items: center;">
				<text class="" :style="order.waitNum && order.status == 2 ?'float: left;':'color: transparent;'">
					待充数:{{ order.waitNum }}
				</text>

				<text class="total-price">
					<text class="" style="font-size: 24rpx;">共{{ order.quantity }}件商品 合计:</text>
					￥{{ priceInt(order.total_price) | showPrice }}
					<text class="decimal">.{{ priceDecimal(order.total_price) | showPrice }}</text>
				</text>
			</view>

		</view>

		<view class="order">
			<view class="title">
				<view class="info">
					订单信息
				</view>
				<view class="copy" data-agl-cvt="1" v-if="order.recharge_info && order.recharge_info.length >0" @click="paste('',2)">
					复制
				</view>
			</view>
			<view class="content">
				<view class="cardlist">
					<view class="info-row" v-if="order.recharge_info.length >0"
						v-for="(item,index) in order.recharge_info" :key="index">
						<view class="info-key">
							{{item.n}}
						</view>
						<view class="info-value">
							<template v-if="item.t == 'images'">
								<div class="img-box" style="display: inline-flex;align-items: center;gap: 10rpx;">
									<div class="img-item" v-for="src,idx in item.v" :key="idx" @click.stop>
										<u-image width="60" height="60" @click="seeImg(idx,item.v)" border-radius="10"
											:src="src"></u-image>
									</div>
								</div>
							</template>
							<template v-else-if="item.t == 'checkbox'">
								{{item.v.join(',')}}
							</template>
							<template v-else>
								{{item.v}}
							</template>
						</view>
					</view>
					<template v-if="order.goods_type == 3">
						<view class="info-row" v-if="order.real_name">
							<view class="info-key">
								收货人姓名
							</view>
							<view class="info-value">
								{{order.real_name}}
							</view>
						</view>
						<view class="info-row" v-if="order.address_mobile">
							<view class="info-key">
								联系电话
							</view>
							<view class="info-value">
								{{order.address_mobile}}
							</view>
						</view>
						<view class="info-row" v-if="order.address">
							<view class="info-key">
								详细地址
							</view>
							<view class="info-value">
								{{order.address}}
							</view>
						</view>
					</template>

					<view class="info-row" v-if="order.pay_type_text">
						<view class="info-key">
							支付方式
						</view>
						<view class="info-value">
							{{ order.pay_type_text }}
						</view>
					</view>
					<view class="info-row" v-if="order.external_orderno">
						<view class="info-key">
							三方单号
						</view>
						<view class="info-value">
							{{ order.external_orderno }}
						</view>
					</view>
					<view class="info-row" v-if="order.recharge_hints">
						<view class="info-key">
							充值返回
						</view>
						<view class="info-value">
							{{ order.recharge_hints }}
						</view>
					</view>
					<view class="info-row" v-if="order.status == 3">
						<view class="info-key">
							完成时间
						</view>
						<view class="info-value">
							{{ $util.timeFormat(order.finish_time,'yyyy-mm-dd hh:MM:ss') }}
						</view>
					</view>
					<view class="info-row" v-if="finishTime != '-'">
						<view class="info-key">
							订单耗时
						</view>
						<view class="info-value">
							{{ finishTime }}
						</view>
					</view>
					<view class="info-row" v-if="order.mark">
						<view class="info-key">
							订单备注
						</view>
						<view class="info-value">
							{{ order.mark }}
						</view>
					</view>

				</view>

				<!-- 	<view class="recharge" v-else>
				
					<view class="info-row" v-if="order.pay_type_text">
						<view class="info-key">
							支付方式
						</view>
						<view class="info-value">
							{{ order.pay_type_text }}
						</view>
					</view>
					<view class="info-row" v-if="order.recharge_hints">
						<view class="info-key">
							充值返回
						</view>
						<view class="info-value">
							{{ order.recharge_hints }}
						</view>
					</view>
					<view class="info-row" v-if="order.status == 3">
						<view class="info-key">
							完成时间
						</view>
						<view class="info-value">
							{{ $util.timeFormat(order.finish_time,'yyyy-mm-dd hh:MM:ss') }}
						</view>
					</view>
					
					
				</view> -->
			</view>
		</view>
		<view class="order" v-if="order.cards && order.cards.length > 0">
			<view class="title">
				<view class="info">
					卡密信息
				</view>
				<view class="copy" data-agl-cvt="1" @click="paste('',1)">
					复制
				</view>
			</view>
			<view class="content">
				<view class="cardlist">
					<view class="info-row" v-for="(item,index) in order.cards" :key="index">
						<view class="info-key" v-if="item.card_no">
							卡号：{{item.card_no}}
						</view>
						<view class="info-value">
							{{order.weidianpro_btn && order.recharge_url && !item.card_no && item.card_password?'序列号':'卡密'}}：{{item.card_password}}
						</view>
						<view class="info-value"
							v-if="order.weidianpro_btn && order.recharge_url && !item.card_no && item.card_password">
							<view class="dhlink" style="background-color: #4a4af9;"
								@click.stop="showRedQrcode(order.recharge_url,item.card_password)">
								点击兑换
							</view>
						</view>
					</view>
				</view>
			</view>
		</view>
		
		<view class="order"
			v-if="!(order.weidianpro_btn && order.recharge_url) && order.cards && order.cards.length == 1 && ((order.cards[0].card_password && !order.cards[0].card_no) || (order.cards[0].card_no && !order.cards[0].card_password))">
			<view class="content">
				<view class="cardlist-qrocde">
					<view class="item" v-for="(item,index) in order.cards" :key="index">
						<view class="img">
							<uqrcode :ref="'uqrcode'+index" :h5SaveIsDownload="false" :canvas-id="'qrcode'+index"
								:value="order.weidianpro_btn && order.recharge_url && !item.card_no && item.card_password ? order.recharge_url + item.card_password :item.card_no + item.card_password" @click="savePosterPath(index)"
								@complete="create_success($event,index)">
								<template v-slot:h5save="{ tempFilePath }">
									<view
										style="display: flex;flex-direction: column;align-items: center;width: 700rpx;padding: 30px 0;background-color: #ffffff;">
										<text style="font-size: 14px;color: #9a9b9c;">若保存失败，请长按二维码进行保存</text>
										<image style="width: 500rpx;height: 500rpx;margin-top: 20px;"
											:src="tempFilePath">
										</image>
									</view>
								</template>
							</uqrcode>
						</view>
						<view class="pass">
							{{item.card_no + item.card_password}}
						</view>
					</view>
				</view>
			</view>
		</view>
		
		
		<view class="order" v-if="order.status == 3 && order.order_notice">
			<view class="title">
				使用说明
			</view>
			<view class="content">
				<u-parse :html="order.order_notice"></u-parse>
			</view>
		</view>
		<view class="order" v-if="order.certify_info && order.certify_info.real_name">
			<view class="title">
				<view class="info">
					提单人信息
				</view>
				<view class="copy" @click="strSign = !strSign">
					{{strSign?`查 看`:`隐 藏`}}
				</view>
			</view>
			<view class="content">
				<view class="cardlist">
					<view class="info-row" v-if="order.certify_info.real_name">
						<view class="info-key">
							姓名
						</view>
						<view class="info-value">
							{{order.certify_info.real_name}}
						</view>
					</view>
					<view class="info-row" v-if="order.certify_info.mobile">
						<view class="info-key">
							手机号
						</view>
						<view class="info-value">
							{{strMobile}}
						</view>
					</view>
					<view class="info-row" v-if="order.certify_info.face_img">
						<view class="info-key">
							人脸照片
						</view>
						<view class="info-value">
							<div class="img-box" style="display: inline-flex;align-items: center;gap: 10rpx;">
								<div class="img-item" @click.stop>
									<u-image width="60" height="60"
										@click="seeImg(0,[strSign?'人脸照片':order.certify_info.face_img])"
										border-radius="10" :src="strSign?'人脸照片':order.certify_info.face_img"></u-image>
								</div>
							</div>
						</view>
					</view>
					<view class="info-row" v-if="order.certify_info.card_no">
						<view class="info-key">
							身份证
						</view>
						<view class="info-value">
							{{strCardNo}}
						</view>
					</view>
				</view>
			</view>
		</view>
		<template v-if="expressList && expressList.length>0 ">
			<view class="order" v-for="(item,index) in expressList" :key="index">
				<view class="title">
					<view class="info">
						物流信息 <u-tag :text="item.express_name" size="mini" :closeable="false" />
					</view>
					<view class="copy" @click="paste(item.express_no)">
						{{item.express_no}} 复制
					</view>
				</view>
				<view class="content" style="padding:4rpx;">
					<u-time-line v-if="item.content && item.content.length>0">
						<view class="u-order-title">【{{item.status}}】</view>
						<u-time-line-item v-for="(item1,index1) in item.content" :key="index1">
							<template v-slot:content>
								<view>
									<view class="u-order-desc">{{item1.status}}</view>
									<view class="u-order-time">{{item1.time}}</view>
								</view>
							</template>
						</u-time-line-item>
					</u-time-line>
				</view>
			</view>

		</template>
		<view class="footer">
			<view class="tool">
				<view class="item" style="background-color: #4a4af9;" @click.stop="goTo('/pages/index/index')">
					返回首页
				</view>
				<view class="item" style="background-color: #4a4af9;" @click.stop="kefu">
					联系客服
				</view>
				<view class="item" v-if="order.cards && order.cards.length > 0" style="background-color: #b55be7;"
					@click.stop="create_qrcode">
					生成二维码
				</view>
				<view class="item" @click="goTo('/pages/buyer/addcomplain?ordersn='+order.ordersn)"
					v-if="[1,2,3].indexOf(order.status) != -1">
					申请售后
				</view>
				<view class="item" style="background-color: #ff0000;"
					@click.stop="goTo(`/pages/activity/goods_combination_status/index?id=${order.groups_log_id}`)"
					v-if="order.type == 1">
					查看拼团
				</view>

				<!-- <view class="item" style="background-color: #4a4af9;" @click="paste1(2)" v-if="qq_group_url != ''">
					加入售后群
				</view> -->
			</view>
		</view>
		<u-popup v-model="qrcodeshow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
			:border-radius="20" width="500rpx" :closeable="true" @close="qrcodeshow = false">
			<view class="popup-content">
				<view class="title" style="color:red">
					长按识别领取红包封面
				</view>
				<view class="qrcode">
					<uqrcode :hide="!qrcode_image_show" :loading="true" v-if="!qrcode_image_show"
						@complete="uqrcodeComplete" ref="uqrcode" @longpress="saveqrcode" canvas-id="qrcode"
						sizeUnit="rpx" size="300" :value="qrcode_url"></uqrcode>
					<image style="width: 100%;height: 100%;" v-if="qrcode_image_show" :src="qrcode_image"
						mode="aspectFit"></image>
				</view>
				<view>
					<view style="color:red">{{' '}}</view>
				</view>
			</view>
		</u-popup>

	</view>
</template>


<script>
	export default {
		data() {
			return {
				imgList: [

				], //卡密二维码
				strSign: true,
				qrcodeshow: false,
				qrcode_image_show: false,
				qrcode_image: '',
				qrcode_card: '',
				qrcode_url: '', //红包封面二维码

				sys: this.$util.sys(),
				order: {
					id: '',
					ordersn: '',
					total_price: '0.00',
					price: '0.00',
					status: '0',
					recharge_hints: '',
				},
				floor_goods: [],
				statusColor: {
					'-1': {
						color: '#999'
					},
					'0': {
						color: '#999'
					},
					'1': {
						color: '#f7b24b'
					},
					'2': {
						color: '#ff8507'
					},
					'3': {
						color: '#90dd90'
					},
					'4': {
						color: '#ff5500'
					},
					'5': {
						color: '#ff5500'
					}
				},

				basic_business_qq: '', //售后qq
				qq_group_url: '', //售后qq群
				is_have_complain: false, //是否存在售后
				kefulink: '', //客服链接
				myInterv: null,
				finishTime: '-',
				expressList: [],

				refushNum: 5,
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		computed: {
			// 价格小数
			priceDecimal() {
				return val => {

					if (val !== parseInt(val)) return val.split('.')[1];
					else return '00';
				};
			},
			// 价格整数
			priceInt() {
				return val => {

					if (val !== parseInt(val)) return val.split('.')[0];
					else return val;
				};
			},
			orderProgressVisible() {
				const {
					goods_type
				} = this.order
				return goods_type == 2 && this.orderProgressNum ? true : false
			},
			orderProgressNum() {
				const {
					current_progress,
					target_progress
				} = this.order
				if (target_progress)
					return ((current_progress / target_progress) * 100)
				else return 0
			},


			strCardNo() {

				if (this.order.certify_info) {
					if (this.strSign) {
						return this.order.certify_info.card_no.substr(0, 12) + '******';
					}

					return this.order.certify_info.card_no
				}

				return ''
			},
			strMobile() {
				if (this.order.certify_info) {
					if (this.strSign) {
						return String(this.order.certify_info.mobile).replace(/(\d{3})\d{4}(\d{4})/, '$1****$2');
					}
					return this.order.certify_info.mobile
				}
				return ''
			},

		},
		onLoad(e) {
			this.order.id = e.id
			this.loadData();
		},
		methods: {
			savePosterPath(index) {
				this.$refs['uqrcode' + index][0].toTempFilePath({
					success: res => {

						uni.previewImage({
							current: 0, // 当前显示图片的索引值
							urls: [res.tempFilePath], // 需要预览的图片列表，photoList要求必须是数组

						})
					}
				});
			},
			create_success(e, index) {
				this.$refs['uqrcode' + index][0].toTempFilePath({
					success: res => {
						this.imgList[index] = res.tempFilePath
					}
				});
			},
			//二维码生成成功
			uqrcodeComplete(e) {
				this.$refs.uqrcode.toTempFilePath({
					success: res => {
						this.qrcode_image = res.tempFilePath
						this.qrcode_image_show = true
					}
				});
			},
			saveqrcode(e) {
				console.log(e);
			},
			showRedQrcode(recharge_url, qrcode_card) {
				this.qrcode_image_show = false
				this.qrcode_card = qrcode_card
				this.qrcode_url = recharge_url + qrcode_card
				this.qrcodeshow = true;
			},
			seeImg(index, urls) {
				uni.previewImage({
					current: index, // 当前显示图片的索引值
					urls: urls, // 需要预览的图片列表，photoList要求必须是数组

				})
			},
			create_qrcode() {
				uni.setStorage({
					key: 'order_info_data',
					data: JSON.stringify(this.order)
				});
				this.$util.on('/pages/order/createqrcode')
			},

			getFinishTime() {

				if (this.order.finish_time > 0) {
					this.finishTime = this.$util.timeSub(parseInt(this.order.create_time * 1000), parseInt(this.order
						.finish_time * 1000));

				} else {
					if (!this.myInterv) {
						this.myInterv = setInterval(() => {
							let end = new Date().getTime()

							this.finishTime = this.$util.timeSub(parseInt(this.order.create_time * 1000), end);
						}, 1000);

					}

				}


			},
			paste(val, type) {
				if (!val) {
					val = '';
				}
				//充值信息
				if (type == 1) {
					for (let i = 0; i < this.order.cards.length; i++) {

						if (this.order.cards[i].card_no && this.order.cards[i].card_no != '') {
							val += this.order.cards[i].card_no + ' ' + this.order.cards[i]
								.card_password + "\r\n"
						} else {
							val += this.order.cards[i].card_password + "\r\n"
						}
					}
					//#ifdef H5	
					window._agl && window._agl.push(['track', ['success', {
						t: 1
					}]])
					//#endif
				} else if (type == 2) {

					for (let i = 0; i < this.order.recharge_info.length; i++) {
						val += this.order.recharge_info[i].v + "\r\n"
					}
				}
				if (val) {
					val = val.replace(/<br>/ig, '\r\n');
					val = val.replace(/(^\s*)|(\s*$)/g, "");
					val = val.replace(/&amp;/ig, '&');
				}

				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			paste1(type) {

				switch (type) {
					case 1:

						// #ifdef H5


						// window.location.href = 'http://wpa.qq.com/msgrd?v=3&uin=' + this.basic_business_qq +'&site=qq&menu=yes'
						if (!this.$util.browserType('weixin')) {
							window.location.href = 'mqqwpa://im/chat?chat_type=wpa&uin=' + this.basic_business_qq +
								'&version=1'
						} else {
							uni.setClipboardData({
								data: this.basic_business_qq,
								success: function() {
									uni.showToast({
										title: '复制成功请添加客服QQ',
										mask: false,
										duration: 1500,
										icon: 'none'
									});
								}
							})
						}


						// #endif

						// #ifndef H5
						uni.setClipboardData({
							data: this.basic_business_qq,
							success: function() {
								uni.showToast({
									title: '复制成功请浏览器打开添加客服QQ',
									mask: false,
									duration: 1500,
									icon: 'none'
								});
							}
						})
						// #endif
						break;
					case 2:
						// #ifdef H5
						if (!this.$util.browserType('weixin')) {
							window.location.href = this.qq_group_url
						} else {
							uni.setClipboardData({
								data: this.qq_group_url,
								success: function() {
									uni.showToast({
										title: '复制成功请浏览器打开添加售后QQ群',
										mask: false,
										duration: 1500,
										icon: 'none'
									});
								}
							})
						}
						// #endif

						// #ifndef H5
						uni.setClipboardData({
							data: this.qq_group_url,
							success: function() {
								uni.showToast({
									title: '复制成功请添加售后QQ群',
									mask: false,
									duration: 1500,
									icon: 'none'
								});
							}
						})
						// #endif
						break;
				}

			},
			async loadData(type) {
				// this.loading = true;

				if (!type) {
					uni.showLoading({
						mask: true,
						title: '加载中...'
					})
				}

				// let params = {};
				await this.$u.api.orderInfo({
						id: this.order.id
					})
					.then(res => {
						this.order = res.order
						this.floor_goods = res.floor_goods

						this.basic_business_qq = res.basic_business_qq
						this.qq_group_url = res.qq_group_url
						//是否存在售后
						this.is_have_complain = res.is_have_complain
						this.kefulink = res.kefulink
						this.expressList = res.expressList
						//倒计时充值时间
						if (this.order.goods_type == 2 && ['1', '2', '3'].indexOf(this.order.status) !== -1) {
							this.getFinishTime()
						}

						//刷新
						if (this.refushNum > 1 && !(this.order.cards && this.order.cards.length > 0)) {
							setTimeout(() => {


								this.refushNum--;
								this.loadData(1)

							}, 2000)
						}


					}).catch(res => {})

				// this.loading = false;

				if (!type) {
					uni.hideLoading()
				}

			},
			kefu() {
				// if(this.kefulink){
				// 		this.$util.on(kefulink)
				// }else{
				this.$util.on('/pages/index_sub/kefu')
				// }

				//#ifdef H5

				// location.href = this.kefulink

				//#endif

				// #ifndef H5
				// this.$util.on('/pages/common/webview?url=' + this.kefulink)
				// #endif
			},
			goTo(url) {
				this.$util.on(url)
			},
		}

	}
